import React, { useState } from "react";
import "./Men.css";

const menProducts = [
  {
    id: 1,
    name: "Men Shirt",
    price: 49,
    image: require("../assets/men1.jpg"),
  },
  {
    id: 2,
    name: "Men T-Shirt",
    price: 29,
    image: require("../assets/men2.jpg"),
  },
  {
    id: 3,
    name: "Men Jacket",
    price: 89,
    image: require("../assets/men3.jpg"),
  },
  {
    id: 4,
    name: "Men Jeans",
    price: 59,
    image: require("../assets/men4.jpg"),
  },
];

const Men = () => {
  const [qty, setQty] = useState({});

  const increase = (id) => {
    setQty({ ...qty, [id]: (qty[id] || 0) + 1 });
  };

  const decrease = (id) => {
    if (qty[id] > 0) {
      setQty({ ...qty, [id]: qty[id] - 1 });
    }
  };

  return (
    <div className="men-page">
      <h2 className="men-title">Men Collection</h2>

      <div className="men-grid">
        {menProducts.map((item) => (
          <div className="men-card" key={item.id}>
            <img src={item.image} alt={item.name} />
            <h3>{item.name}</h3>
            <p className="price">${item.price}</p>

            <div className="qty-box">
              <button onClick={() => decrease(item.id)}>-</button>
              <span>{qty[item.id] || 0}</span>
              <button onClick={() => increase(item.id)}>+</button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Men;
